# Read long description from README
def read_long_description():
    try:
        with open('README.md', 'r', encoding='utf-8') as f:
            return f.read()
    except FileNotFoundError:
        return "Internal library for company projects"


# Read requirements from requirements.txt with validation
def read_requirements():
    requirements = []
    try:
        with open('requirements.txt', 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                # Skip comments and empty lines
                if line and not line.startswith('#'):
                    # Validate requirement format (basic validation)
                    if any(char in line for char in ['<', '>', '=', '~', '!']):
                        # Has version specifier - good practice
                        requirements.append(line)
                    else:
                        # No version specifier - add warning but allow
                        print(f"Warning: No version specifier for {line}")
                        requirements.append(line)
    except FileNotFoundError:
        # Fallback to pinned versions of common dependencies
        requirements = [
            'numpy>=1.21.0,<2.0.0',
            'requests>=2.28.0,<3.0.0',
            'pyyaml>=6.0,<7.0'
        ]
    
    return requirements


